// src/pages/Destinations.jsx
import React, { useEffect, useState } from 'react';
import { fetchGroups } from '../services/api';  // Cette fonction récupère tous les groupes
import GroupCard from '../components/GroupCard';
import '../styles/Destinations.css';

const Destinations = () => {
    const [groups, setGroups] = useState([]);

    useEffect(() => {
        fetchGroups().then(setGroups);  // Charge tous les groupes (les destinations)
    }, []);

    return (
        <div className="destinations-container">
            <h1 className="destinations-title">Nos Destinations</h1>

            <div className="destinations-grid">
                {groups.map(group => (
                    <GroupCard
                        key={group.id}
                        id={group.id}
                        name={group.name}
                        image={group.image}
                        members={group.members}
                    />
                ))}
            </div>
        </div>
    );
};

export default Destinations;
